import React, { useState, useEffect } from 'react';
import api from '../api/api';

const NutrientWarning = () => {
    const [warnings, setWarnings] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchWarnings = async () => {
            try {
                const response = await api.get('/nutrients/check');
                setWarnings(response.data.warnings);
                setLoading(false);
            } catch (err) {
                console.error("Nutrient check failed:", err);
                setError("Could not run RDI check.");
                setLoading(false);
            }
        };
        fetchWarnings();
    }, []);

    if (loading) return <p className="text-sm text-gray-500">Checking daily nutrient intake...</p>;
    if (error) return <p className="text-sm text-red-500">{error}</p>;

    return (
        <div className="mt-4 p-4 bg-yellow-50 border border-yellow-300 rounded-lg">
            <h4 className="text-md font-bold mb-2 text-yellow-800">⚠️ Nutrient Status Check (Today)</h4>
            
            {warnings.length === 0 ? (
                <p className="text-sm text-green-700">All primary nutrient targets met (or near target) today!</p>
            ) : (
                <ul className="space-y-1">
                    {warnings.map((warn, index) => (
                        <li key={index} className="text-sm text-yellow-900 font-medium">
                            {warn.nutrient}: {warn.message} 
                            (Intake: {warn.intake}{warn.nutrient.includes('(') ? warn.nutrient.split('(')[1].slice(0, -1) : ''} / Target: {warn.target}{warn.nutrient.includes('(') ? warn.nutrient.split('(')[1].slice(0, -1) : ''})
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
};

export default NutrientWarning;
